import numpy as np

rng = np.random.default_rng(0)

def dot(a, b):
    a = np.asarray(a, dtype=float)
    b = np.asarray(b, dtype=float)
    return np.sum(a * b)

probe = np.array([1.0, 0.0])

c1 = np.array([3.0, 0.0])
c2 = np.array([0.0, 3.0])
c3 = np.array([-3.0, 0.0])
c4 = np.array([2.0, 2.0])

candidates = {"c1": c1, "c2": c2, "c3": c3, "c4": c4}

scores = {name: dot(probe, vec) for name, vec in candidates.items()}
for name, score in scores.items():
    print(name, "->", score)

probe_turned = np.array([0.0, 1.0])

scores_turned = {name: dot(probe_turned, vec) for name, vec in candidates.items()}
for name, score in scores_turned.items():
    print(name, "->", score)

assert scores_turned["c2"] > scores_turned["c1"]
assert scores["c1"] > scores["c2"]

def multiply_and_add(a, b):
    """Multiply entry by entry, then add. That's the whole recipe."""
    return np.sum(a * b)

scores = {name: multiply_and_add(probe, vec) for name, vec in candidates.items()}
print(scores)

for name, vec in candidates.items():
    assert multiply_and_add(probe, vec) == np.dot(probe, vec)

print("c1 has the top score:", scores["c1"] == max(scores.values()))

def vec(angle_deg, length=1.0):
    a = np.deg2rad(angle_deg)
    return length * np.array([np.cos(a), np.sin(a)])

probe = vec(40)
c1 = vec(75, 1.0)
c2 = vec(40, 1.0)
c3 = vec(130, 1.0)
c4 = vec(220, 1.0)

candidates = {"c1": c1, "c2": c2, "c3": c3, "c4": c4}
scores = {name: float(np.sum(probe * arrow)) for name, arrow in candidates.items()}

for name, score in scores.items():
    print(name, "score:", round(score, 2))

top_candidate = max(scores, key=scores.get)
print("tops out:", top_candidate)

assert top_candidate == "c2"

def make_vector(angle_deg, length=1.0):
    angle_rad = np.deg2rad(angle_deg)
    return length * np.array([np.cos(angle_rad), np.sin(angle_rad)])

probe = make_vector(40)
candidates = {
    'c1': make_vector(15),
    'c2': make_vector(35),
    'c3': make_vector(130),
    'c4': make_vector(200),
}

print('probe:', np.round(probe, 2))
for name, vec in candidates.items():
    print(name, np.round(vec, 2))

def dot_by_hand(u, v):
    total = 0.0
    for ui, vi in zip(u, v):
        total += ui * vi
    return total

scores = {name: dot_by_hand(probe, vec) for name, vec in candidates.items()}
for name, score in scores.items():
    print(name, 'score:', round(score, 2))

winner = max(scores, key=scores.get)
print('tops out:', winner)

for name, vec in candidates.items():
    assert np.isclose(dot_by_hand(probe, vec), np.dot(probe, vec))

print('the hand-rolled loop matches np.dot on every candidate')

candidate_angles_deg = {"c1": 0, "c2": 45, "c3": 90, "c4": 200}
candidates = {
    name: np.array([np.cos(np.radians(deg)), np.sin(np.radians(deg))])
    for name, deg in candidate_angles_deg.items()
}

probe_angles = np.linspace(0, 2 * np.pi, 360, endpoint=False)
for name, c in candidates.items():
    scores = np.array([np.dot(np.array([np.cos(t), np.sin(t)]), c) for t in probe_angles])
    print(f"{name}: min={scores.min():.2f}  max={scores.max():.2f}")

# Every candidate here is a unit-length arrow, and none of them move.
# With length held fixed, some score still dips below zero as the probe
# turns around.
assert all(
    np.array([np.dot(np.array([np.cos(t), np.sin(t)]), c) for t in probe_angles]).min() < 0
    for c in candidates.values()
)
